const express = require('express');
const elasticsearch = require('elasticsearch');
const { validate } = require('jsonschema');

const app = express();
const client = new elasticsearch.Client({
  host: 'http://localhost:9200',
});

// Define the schema for search parameters
const searchParamsSchema = {
  type: 'object',
  properties: {
    query: {
      type: 'string',
    },
    filters: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          field: {
            type: 'string',
          },
          value: {
            type: 'string',
          },
        },
      },
    },
  },
};

// Define the schema for custom scoring scripts
const scoringScriptSchema = {
  type: 'object',
  properties: {
    script: {
      type: 'string',
    },
  },
};

app.post('/search', async (req, res) => {
  // Validate the search parameters against the schema
  const validationResult = validate(req.body, searchParamsSchema);
  if (!validationResult.valid) {
    return res.status(400).json({ message: 'Invalid search parameters' });
  }

  // Build the Elasticsearch query DSL using the search parameters
  const query = {
    bool: {
      must: [
        {
          match: {
            _all: req.body.query,
          },
        },
      ],
      filter: [],
    },
  };

  // Add filters to the query if they are provided
  if (req.body.filters) {
    for (const filter of req.body.filters) {
      query.bool.filter.push({
        term: {
          [filter.field]: filter.value,
        },
      });
    }
  }

  // Apply custom scoring if a script is provided
  if (req.body.scoringScript) {
    const validationResult = validate(req.body.scoringScript, scoringScriptSchema);
    if (!validationResult.valid) {
      return res.status(400).json({ message: 'Invalid custom scoring script' });
    }
    query.script_score = {
      script: req.body.scoringScript.script,
    };
  }

  // Execute the Elasticsearch query and return the results
  const response = await client.search({
    index: 'my-index',
    body: query,
  });
  res.json(response);
});